const f=[0,null,1,null,2,3,null,4,null,5,null,6];function d(s,r){const l=s.length>>1,n=new Float32Array(l);for(let t=1;t<l;t++){let e=0;for(let o=0;o<l;o++){const c=s[o]-s[o+t];e+=c*c}n[t]=e}n[0]=1;let a=0;for(let t=1;t<l;t++)a+=n[t],n[t]=n[t]*t/a;for(let t=2;t<l-1;t++)if(n[t]<.15&&n[t]<=n[t+1]){const e=n[t-1],o=n[t],c=n[t+1],u=2*(2*o-e-c),i=u===0?t:t+(c-e)/u;return r/i}return-1}self.onmessage=({data:{samples:s,sampleRate:r}})=>{const l=d(s,r);if(l<50||l>2100){self.postMessage({noteIdx:null,hz:l});return}const a=(Math.round(12*Math.log2(l/440)+69)%12+12)%12,t=f[a]??null;self.postMessage({noteIdx:t,hz:l})};
